// Fonction de recherche par nom de commune ou code INSEE
export function searchCommunes(query: string): CommuneData[] {
  const normalizedQuery = query.toLowerCase().trim();
  if (normalizedQuery.length < 2) return [];

  return communes.filter((commune) =>
    commune.name.toLowerCase().includes(normalizedQuery) ||
    commune.inseeCode.includes(normalizedQuery)
  );
}

// Fonction de recherche par code INSEE
export function searchByInseeCode(code: string): CommuneData | undefined {
  return communes.find((commune) => commune.inseeCode === code);
}

// Fonction pour obtenir le type de taxe d'une commune
export function getTaxType(communeName: string): TaxType | null {
  const commune = communes.find(
    (c) => c.name.toLowerCase() === communeName.toLowerCase()
  );
  return commune ? commune.taxType : null;
}
